const isoDate = $now.toFormat('yyyy-MM-dd');
const parts = isoDate.split('-');
const dd = parts[2];
const mm = parts[1];
const yy = parts[0].slice(2);
const dateLabel = `${dd}-${mm}-${yy}`;
const date30DaysAgo = $now.minus({ days: 30 }).toFormat('yyyy-MM-dd');
return [{ json: { isoDate, dateLabel, date30DaysAgo, pageTitle: `AI-Updates-${dateLabel}` } }];

const PROVIDERS = [
  { key: 'openai', label: 'OpenAI' },
  { key: 'anthropic', label: 'Anthropic' },
  { key: 'google', label: 'Google' },
  { key: 'x-ai', label: 'xAI' },
  { key: 'deepseek', label: 'DeepSeek' },
  { key: 'qwen', label: 'Qwen' },
  { key: 'meta-llama', label: 'Meta' },
  { key: 'minimax', label: 'MiniMax' },
  { key: 'moonshotai', label: 'Moonshot AI' },
  { key: 'mistralai', label: 'Mistral' },
  { key: 'z-ai', label: 'Z.AI' },
  { key: 'microsoft', label: 'Microsoft' }
];
const EXCLUDE = /embed|tts|speech|rerank|whisper|vision-only|image-gen/i;
const data = $input.first().json;
const allModels = data.data || [];
const nowSec = Math.floor($now.toSeconds());
const weekAgo = Math.floor($now.minus({ days: 7 }).toSeconds());
function toM(p) {
  const n = parseFloat(p || '0');
  return isNaN(n) ? '?' : '$' + (n * 1e6).toFixed(2);
}
function ctx(n) {
  return n ? Math.round(n / 1000) + 'K' : '?';
}
const viable = allModels.filter(m => m.id && !EXCLUDE.test(m.id) && m.pricing?.prompt !== undefined);
const newThisWeek = viable
  .filter(m => m.created && m.created > weekAgo)
  .sort((a, b) => (b.created || 0) - (a.created || 0))
  .slice(0, 8);
const dateStr = $now.toFormat('yyyy-MM-dd');
let lines = ['---', '## Model Pricing Dashboard', '> Live from OpenRouter - ' + dateStr + ' - All prices in $/1M tokens', ''];
if (newThisWeek.length) {
  lines.push('### New This Week', 'Models added to OpenRouter in the last 7 days:');
  for (const m of newThisWeek) {
    const da = m.created ? Math.floor((nowSec - m.created) / 86400) + 'd ago' : '';
    lines.push('- **' + (m.name || m.id) + '** - ' + toM(m.pricing?.prompt) + ' input / ' + toM(m.pricing?.completion) + ' output - ' + ctx(m.context_length) + ' ctx' + (da ? ' - ' + da : ''));
  }
  lines.push('');
}
for (const prov of PROVIDERS) {
  const models = viable
    .filter(m => m.id.startsWith(prov.key + '/'))
    .sort((a, b) => (b.created || 0) - (a.created || 0))
    .slice(0, 5);
  if (!models.length) continue;
  lines.push('### ' + prov.label);
  for (const m of models) {
    lines.push('- **' + (m.name || m.id.split('/').pop()) + '** - ' + toM(m.pricing?.prompt) + ' input / ' + toM(m.pricing?.completion) + ' output - ' + ctx(m.context_length) + ' ctx');
  }
  lines.push('');
}
lines.push('[' + PROVIDERS.map(p => p.label).join(' - ') + ']');

return [{ json: { pricingSection: lines.join('\\n'), selectedModel: 'openrouter/free' } }];

const aiResponse = $input.first().json;
const fullText = aiResponse.choices?.[0]?.message?.content || '';
const dateInfo = $('Node 2: Get Current Date').first().json;
if (!fullText) throw new Error('Node 6 returned empty content from AI');

// 1. Extract JSON properties block
const jsonFenceMatch = fullText.match(/```json([\s\S]*?)```/);
let metadata = {};
if (jsonFenceMatch) {
  try { metadata = JSON.parse(jsonFenceMatch[1].trim()); } catch (e) { metadata = { parseError: e.message }; }
}
const afterJsonBlock = jsonFenceMatch ? fullText.slice(fullText.indexOf(jsonFenceMatch[0]) + jsonFenceMatch[0].length).trim() : fullText.trim();

// 2. Inline rich_text parser — handles **bold** and [text](url)
const MAX_RT = 1800;
function makeTextRt(content, annotations) {
  const rt = [];
  let remaining = content;
  while (remaining.length > 0) {
    const chunk = remaining.slice(0, MAX_RT);
    remaining = remaining.slice(MAX_RT);
    const obj = { type: 'text', text: { content: chunk } };
    if (annotations && Object.keys(annotations).length) obj.annotations = annotations;
    rt.push(obj);
  }
  return rt;
}
function parseInlineRichText(line) {
  const rt = [];
  const pattern = /\*\*([^*]+)\*\*|\[([^\]]+)\]\(([^)]+)\)/g;
  let lastIdx = 0;
  let match;
  while ((match = pattern.exec(line)) !== null) {
    if (match.index > lastIdx) rt.push(...makeTextRt(line.slice(lastIdx, match.index), {}));
    if (match[1] !== undefined) {
      rt.push(...makeTextRt(match[1], { bold: true }));
    } else if (match[2] !== undefined) {
      let txt = match[2];
      const url = match[3];
      while (txt.length > 0) {
        rt.push({ type: 'text', text: { content: txt.slice(0, MAX_RT), link: { url } } });
        txt = txt.slice(MAX_RT);
      }
    }
    lastIdx = match.index + match[0].length;
  }
  if (lastIdx < line.length) rt.push(...makeTextRt(line.slice(lastIdx), {}));
  return rt.length ? rt : [{ type: 'text', text: { content: '' } }];
}

// 3. markdownToBlocks
function markdownToBlocks(md) {
  const lines = md.split('\n');
  const blocks = [];
  for (const rawLine of lines) {
    const line = rawLine.trimEnd();
    if (line.startsWith('## ')) {
      blocks.push({ object: 'block', type: 'heading_2', heading_2: { rich_text: parseInlineRichText(line.slice(3).trim()) } });
    } else if (line.startsWith('### ')) {
      blocks.push({ object: 'block', type: 'heading_3', heading_3: { rich_text: parseInlineRichText(line.slice(4).trim()) } });
    } else if (line.startsWith('# ')) {
      blocks.push({ object: 'block', type: 'heading_1', heading_1: { rich_text: parseInlineRichText(line.slice(2).trim()) } });
    } else if (/^[-*] /.test(line)) {
      blocks.push({ object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: parseInlineRichText(line.replace(/^[-*] /, '').trim()) } });
    } else if (/^\d+\. /.test(line)) {
      blocks.push({ object: 'block', type: 'numbered_list_item', numbered_list_item: { rich_text: parseInlineRichText(line.replace(/^\d+\. /, '').trim()) } });
    } else if (line.trim() === '---') {
      blocks.push({ object: 'block', type: 'divider', divider: {} });
    } else if (line.startsWith('> ')) {
      blocks.push({ object: 'block', type: 'quote', quote: { rich_text: parseInlineRichText(line.slice(2).trim()) } });
    } else if (line.trim() !== '') {
      blocks.push({ object: 'block', type: 'paragraph', paragraph: { rich_text: parseInlineRichText(line.trim()) } });
    }
  }
  return blocks;
}

// 4. Split into chunks of 100
const CHUNK = 100;
const allBlocks = markdownToBlocks(afterJsonBlock);
const chunks = [];
for (let i = 0; i < allBlocks.length; i += CHUNK) chunks.push(allBlocks.slice(i, i + CHUNK));

// 5. Notion property builders
const ms = arr => ({ multi_select: (Array.isArray(arr) ? arr : []).map(n => ({ name: String(n).slice(0, 100) })) });
const sel = n => ({ select: n ? { name: String(n).slice(0, 100) } : null });
const cb = v => ({ checkbox: !!v });
const rt = t => ({ rich_text: [{ type: 'text', text: { content: String(t || '').slice(0, 2000) } }] });

const notionProperties = {
  'Name': { title: [{ text: { content: dateInfo.pageTitle } }] },
  'Date': { date: { start: dateInfo.isoDate } },
  'Category': ms(metadata.category),
  'Topics': ms(metadata.topics),
  'Providers': ms(metadata.providers),
  'Featured Models': ms(metadata.featured_models),
  'Importance': sel(metadata.importance),
  'Report Type': sel('Daily'),
  'Summary': rt(metadata.summary),
  'New Model Released': cb(metadata.new_model_released),
  'Pricing Changed': cb(metadata.pricing_changed),
  'Open Source': cb(metadata.open_source),
  'Free Promotion': cb(metadata.free_promotion),
  'Worth Installing': cb(metadata.worth_installing),
  'Best Coding Model': sel(metadata.best_coding_model),
  'Best Reasoning Model': sel(metadata.best_reasoning_model),
  'Best Local Model': sel(metadata.best_local_model),
  'Best Value API': sel(metadata.best_value_api),
  'Biggest Release': sel(metadata.biggest_release)
};

// 6. Extract executive summary + first 3 bullets for Slack
let execSummary = '';
const execMatch = afterJsonBlock.match(/## Executive Summary[\s\S]*?(?=\n## |$)/);
if (execMatch) {
  execSummary = execMatch[0].replace('## Executive Summary', '').trim().split('\n').find(l => l.trim() && !l.startsWith('#') && !l.startsWith('-')) || '';
}
const bullets = [];
for (const line of afterJsonBlock.split('\n')) {
  if (/^[-*] /.test(line)) { bullets.push(line.replace(/^[-*] /, '').trim()); if (bullets.length >= 3) break; }
}

// 7. Generate SSH Command for Node 10 (base64-safe)
const b64 = Buffer.from(afterJsonBlock).toString('base64');
const sshCommand = `mkdir -p /home/ubuntu/reports && python3 -c "import base64; open('/home/ubuntu/reports/${dateInfo.isoDate}.md','w').write(base64.b64decode('${b64}').decode('utf-8'))" && find /home/ubuntu/reports/ -name '*.md' -mtime +30 -delete && echo 'Saved: /home/ubuntu/reports/${dateInfo.isoDate}.md'`;

return [{ json: { notionProperties, blockChunks: chunks, fullMarkdown: afterJsonBlock, importance: metadata.importance || 'Medium', execSummary: execSummary.slice(0, 500), top3Bullets: bullets, chunkCount: chunks.length, totalBlocks: allBlocks.length, sshCommand } }];

const pageData = $('Node 8: Create Notion Page').first().json;
const pageId = pageData.id;
if (!pageId) throw new Error('No page_id from Node 8: ' + JSON.stringify(pageData).slice(0, 200));
const token = $env.NOTION_INTEGRATION_TOKEN || '';
if (!token) throw new Error('NOTION_INTEGRATION_TOKEN is missing from environment');
const notionAuthHeader = token.startsWith('Bearer ') ? token : 'Bearer ' + token;
const chunks = $('Node 7: Parse + markdownToBlocks').first().json.blockChunks || [];

async function appendChunk(chunk) {
  return await this.helpers.httpRequest({
    method: 'PATCH',
    url: `https://api.notion.com/v1/blocks/${pageId}/children`,
    headers: { 'Authorization': notionAuthHeader, 'Notion-Version': '2022-06-28', 'Content-Type': 'application/json' },
    body: { children: chunk },
    timeout: 30000
  });
}

const results = [];
for (let i = 0; i < chunks.length; i++) {
  let success = false; let lastErr = null;
  for (let attempt = 1; attempt <= 3; attempt++) {
    try {
      await appendChunk.call(this, chunks[i]);
      results.push({ chunk: i + 1, status: 'ok', blocks: chunks[i].length });
      success = true; break;
    } catch (err) {
      lastErr = err.response?.data?.message || err.message;
      if (attempt < 3) await new Promise(r => setTimeout(r, attempt * 2000));
    }
  }
  if (!success) results.push({ chunk: i + 1, status: 'error', error: lastErr, blocks: chunks[i].length });
  if (i < chunks.length - 1) await new Promise(r => setTimeout(r, 300));
}

const failedChunks = results.filter(r => r.status === 'error');
if (failedChunks.length > 0) {
  const details = failedChunks.map(f => `Chunk ${f.chunk}: ${f.error}`).join('; ');
  throw new Error(`Failed to append ${failedChunks.length} of ${chunks.length} block chunks to Notion page. Details: ${details}`);
}

return [{ json: { pageId, notionPageUrl: pageData.url || `https://notion.so/${pageId.replace(/-/g, '')}`, chunksAppended: results.filter(r => r.status === 'ok').length, chunkErrors: failedChunks.length, totalChunks: chunks.length, chunkResults: results } }];

const date30DaysAgo = $('Node 2: Get Current Date').first().json.date30DaysAgo;
const notionAuthHeader = 'Bearer ' + $env.NOTION_INTEGRATION_TOKEN;
const dbId = $env.NOTION_DATABASE_ID;

let oldPages = [];
try {
  const queryRes = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.notion.com/v1/databases/${dbId}/query`,
    headers: { 'Authorization': notionAuthHeader, 'Notion-Version': '2022-06-28', 'Content-Type': 'application/json' },
    body: JSON.stringify({
      filter: {
        and: [
          { property: 'Date', date: { before: date30DaysAgo } },
          { property: 'Report Type', select: { equals: 'Daily' } }
        ]
      }
    }),
    timeout: 15000
  });
  const parsed = typeof queryRes === 'string' ? JSON.parse(queryRes) : queryRes;
  oldPages = parsed.results || [];
} catch (err) {
  return [{ json: { archived: 0, errors: 1, message: 'Query failed: ' + err.message } }];
}

let archived = 0; let errors = 0;
for (const page of oldPages) {
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `https://api.notion.com/v1/pages/${page.id}`,
      headers: { 'Authorization': notionAuthHeader, 'Notion-Version': '2022-06-28', 'Content-Type': 'application/json' },
      body: JSON.stringify({ archived: true }),
      timeout: 10000
    });
    archived++;
    await new Promise(r => setTimeout(r, 200));
  } catch (err) { errors++; }
}

return [{ json: { oldPagesFound: oldPages.length, archived, errors, cutoffDate: date30DaysAgo } }];

const results = $input.first().json.results || [];
const isoDate = $now.toFormat('yyyy-MM-dd');
const parts = isoDate.split('-');
const weekLabel = `${parts[2]}-${parts[1]}-${parts[0].slice(2)}`;

const summaries = results.map(p => {
  const props = p.properties || {};
  const titleProp = Object.values(props).find(v => v.type === 'title');
  const title = titleProp?.title?.[0]?.plain_text || 'Untitled';
  const summaryProp = props['Summary'];
  const summary = summaryProp?.rich_text?.[0]?.plain_text || '';
  const importanceProp = props['Importance'];
  const importance = importanceProp?.select?.name || '';
  return `- ${title}${importance ? ' [' + importance + ']' : ''}${summary ? ': ' + summary.slice(0, 200) : ''}`;
}).join('\n');

const prompt = `You are an AI industry analyst writing a WEEKLY summary report.

Today is ${isoDate} (Sunday). Below are this week's 7 daily AI briefing summaries:

${summaries || 'No daily reports found for this week.'}

Write a comprehensive Weekly AI Intelligence Report in Markdown.

OUTPUT in this exact order:

First: a JSON block (for Notion properties):
\`\`\`json
{
  "summary": "2-3 sentence weekly wrap-up summary",
  "category": ["Frontier Models"],
  "topics": ["Frontier Models", "Open Source"],
  "providers": ["OpenAI"],
  "featured_models": ["GPT-5"],
  "importance": "High",
  "new_model_released": false,
  "pricing_changed": false,
  "open_source": false,
  "free_promotion": false,
  "worth_installing": false,
  "best_coding_model": "",
  "best_reasoning_model": "",
  "best_local_model": "",
  "best_value_api": "",
  "biggest_release": ""
}
\`\`\`

Then the weekly summary report body:
## Weekly Executive Summary
The 5 biggest stories of the week.
## Top Model Releases This Week
All frontier and open-source models launched.
## Biggest Pricing Changes
Any pricing moves worth noting.
## Coding Tool Updates
Updates to Cursor, Claude Code, Gemini CLI, Codex, Windsurf, etc.
## Best Picks This Week
- Best Coding Model of the week
- Best Reasoning Model of the week
- Best Local Model of the week
- Best Value API of the week
## Biggest Disappointment
Any hyped releases that underdelivered.
## Next Week Predictions
2-3 data-driven predictions based on this week's trends.

Rules: Be concise, specific, no filler. Use **bold** for model names. Use bullet lists. No markdown tables.`;

return [{ json: { prompt, weekLabel } }];

